const isPhone = () => /Phone/i.test(navigator.userAgent);

// 检测是否为平板设备  
const isTablet = () => /Tablet/i.test(navigator.userAgent);

// 检测是否为2in1设备  
const is2in1 = () => /PC/i.test(navigator.userAgent);
